  7	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  8	import { PaginatedListPage, ListFilter } from '@odf/shared/list-page';
  9	import { CommonModalProps } from '@odf/shared/modals';
 10	import { S3Commands } from '@odf/shared/s3';
 11	import { getName } from '@odf/shared/selectors';
 12	import { RowComponentType } from '@odf/shared/table';
 13	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 14	import { sortRows } from '@odf/shared/utils';
 15	import { TFunction } from 'react-i18next';
 16	import { Trans } from 'react-i18next';
 17	import {
 18	  Modal,
 19	  ModalVariant,
 20	  Button,
 21	  ButtonVariant,
 22	  TextInput,
 23	  TextInputTypes,
 24	  FormGroup,
 25	  PaginationVariant,
 26	  Checkbox,
 27	  Alert,
 28	  AlertVariant,
 29	} from '@patternfly/react-core';
 30	import { Tr, Td, TableVariant } from '@patternfly/react-table';
 31	import { ObjectCrFormat } from '../../../types';
 32	import { replacePathFromName, getObjectVersionId } from '../../../utils';
 33	import './delete-objects.scss';
 34	
 35	const DELETE = 'delete';
 36	
 37	export type ObjectsDeleteResponse = {
 38	  selectedObjects: ObjectCrFormat[];
 39	  deleteResponse: DeleteObjectsCommandOutput;
 40	};
 41	
 42	export type SetObjectsDeleteResponse = React.Dispatch<
 43	  React.SetStateAction<ObjectsDeleteResponse>
 44	>;
 45	
 46	type DeleteObjectsModalProps = {
 47	  foldersPath: string;
 48	  bucketName: string;
 49	  s3Client: S3Commands;
 50	  objects: ObjectCrFormat[];
 51	  setDeleteResponse: SetObjectsDeleteResponse;
 52	  refreshTokens?: () => Promise<void>;
 53	  closeObjectSidebar?: () => void;
 54	  showVersioning: boolean;
 55	  isVersioningEnabledOrSuspended: boolean;
 56	};
 57	
 58	const getTextInputLabel = (t: TFunction) => (
 59	  <Trans t={t as any}>
 60	    <b>
 61	      To confirm deletion, type <i>{{ delete: DELETE }}</i>:
 62	    </b>
 63	  </Trans>
 64	);
 65	
 66	const getTitle = (
 67	  data: ObjectCrFormat[],
 68	  showVersioning: boolean,
 69	  t: TFunction
 70	) => {
 71	  const isMultiDelete = data.length > 1;
 72	  if (showVersioning)
 73	    return isMultiDelete ? t('Delete versions?') : t('Delete version?');
 74	
 75	  return isMultiDelete ? t('Delete objects?') : t('Delete object?');
 76	};
 77	
 78	const getDescription = (showVersioning: boolean, t: TFunction) => {
 79	  if (showVersioning) {
 80	    return (
 81	      <Trans t={t}>
 82	        <p className="text-muted">
 83	          Deleting a specific version of an object is permanent and cannot be
 84	          undone.
 85	        </p>
 86	        <p className="text-muted">
 87	          Removing a delete marker will restore the object to its most recent
 88	          version, making it accessible again. If no previous versions exist,
 89	          the object will be permanently deleted.
 90	        </p>
 91	      </Trans>
 92	    );
 93	  }
 94	
 95	  return (
 96	    <div className="text-muted">
 97	      {t(
 98	        'Deleted objects will no longer be visible in the bucket. If versioning is enabled, a delete marker is created, allowing recovery from previous versions. For unversioned buckets, deletion is permanent and cannot be undone.'
 99	      )}
100	    </div>
101	  );
102	};
103	
104	const getColumnNames = (t: TFunction) => [
105	  t('Object name'),
106	  t('Size'),
107	  t('Last modified'),
108	];
109	
110	const getVersioningColumnName = (t: TFunction): string => t('Version ID');
111	
112	const getHeaderColumns = (showVersioning: boolean, t: TFunction) => {
113	  const columnNames = getColumnNames(t);
114	  const versioningColumnName = getVersioningColumnName(t);
115	
116	  return [
117	    {
118	      columnName: columnNames[0],
119	      sortFunction: (a, b, c) => sortRows(a, b, c, 'metadata.name'),
120	    },
121	    ...(showVersioning
122	      ? [
123	          {
124	            columnName: versioningColumnName,
125	            sortFunction: (a, b, c) =>
126	              sortRows(a, b, c, 'apiResponse.versionId'),
127	          },
128	        ]
129	      : []),
130	    {
131	      columnName: columnNames[1],
132	      sortFunction: (a, b, c) => sortRows(a, b, c, 'apiResponse.size'),
133	    },
134	    {
135	      columnName: columnNames[2],
136	      sortFunction: (a, b, c) => sortRows(a, b, c, 'apiResponse.lastModified'),
137	    },
138	  ];
139	};
140	
141	const DeleteObjectsTableRow: React.FC<RowComponentType<ObjectCrFormat>> = ({
142	  row: object,
143	  extraProps,
144	}) => {
145	  const { t } = useCustomTranslation();
146	
147	  const { foldersPath, showVersioning } = extraProps;
148	  const name = replacePathFromName(object, foldersPath);
149	
150	  const columnNames = getColumnNames(t);
151	  const versioningColumnName = getVersioningColumnName(t);
152	
153	  return (
154	    <Tr>
155	      <Td dataLabel={columnNames[0]}>{name}</Td>
156	      {showVersioning && (
157	        <Td dataLabel={versioningColumnName}>{object.apiResponse.versionId}</Td>
158	      )}
159	      <Td dataLabel={columnNames[1]}>{object.apiResponse.size}</Td>
160	      <Td dataLabel={columnNames[2]}>{object.apiResponse.lastModified}</Td>
161	    </Tr>
162	  );
163	};
164	
165	const DeleteObjectsModal: React.FC<
166	  CommonModalProps<DeleteObjectsModalProps>
167	> = ({
168	  closeModal,
169	  isOpen,
170	  extraProps: {
171	    foldersPath,
172	    bucketName,
173	    s3Client,
174	    objects: data,
175	    setDeleteResponse,
176	    refreshTokens,
177	    closeObjectSidebar,
178	    showVersioning,
179	    isVersioningEnabledOrSuspended,
180	  },
181	}) => {
182	  const { t } = useCustomTranslation();
183	
184	  const [deleteText, setDeleteText] = React.useState<string>('');
185	  const [inProgress, setInProgress] = React.useState<boolean>(false);
186	  const [error, setError] = React.useState<Error>();
187	  const [permanentDelete, setPermanentDelete] = React.useState<boolean>(false);
188	
189	  // only allow this when deleting single object (not for group/bulk deletion),
190	  // when "List all versions" is off, and versioning is either "Enabled or Suspended" (not disabled)
191	  const allowPermanentDeletion =
192	    isVersioningEnabledOrSuspended && !showVersioning && data.length === 1;
193	
194	  const onDelete = async (event) => {
195	    event.preventDefault();
196	    setInProgress(true);
197	
198	    try {
199	      if (permanentDelete) {
200	        const objectKey = getName(data[0]); // only allowed when deleting single object (not for group/bulk deletion)
201	        let successfullyDeletedObjectVersions: DeletedObject[] = [];
202	        let isTruncated = true;
203	        let stopFetchEarly = false;
204	        let keyMarker: string;
205	        let versionIdMarker: string;
206	        let deleteResponse: DeleteObjectsCommandOutput;
207	
208	        while (isTruncated && !stopFetchEarly) {
209	          const deleteVersionKeys: ObjectIdentifier[] = [];
210	
211	          // eslint-disable-next-line no-await-in-loop
212	          const objectVersions = await s3Client.listObjectVersions({
213	            Bucket: bucketName,
214	            Prefix: objectKey,
215	            KeyMarker: keyMarker,
216	            VersionIdMarker: versionIdMarker,
217	          });
218	
219	          for (const v of objectVersions?.Versions || []) {
220	            if (v.Key === objectKey)
221	              deleteVersionKeys.push({
222	                Key: objectKey,
223	                VersionId: v.VersionId,
224	              });
225	            else stopFetchEarly = true;
226	          }
227	
228	          for (const d of objectVersions?.DeleteMarkers || []) {
229	            if (d.Key === objectKey)
230	              deleteVersionKeys.push({
231	                Key: objectKey,
232	                VersionId: d.VersionId,
233	              });
234	            else stopFetchEarly = true;
235	          }
236	
237	          // eslint-disable-next-line no-await-in-loop
238	          deleteResponse = await s3Client.deleteObjects({
239	            Bucket: bucketName,
240	            Delete: { Objects: deleteVersionKeys },
241	          });
242	          successfullyDeletedObjectVersions = [
243	            ...successfullyDeletedObjectVersions,
244	            ...(deleteResponse.Deleted || []),
245	          ];
246	          if (deleteResponse.Errors?.length > 0) stopFetchEarly = true;
247	
248	          isTruncated = objectVersions.IsTruncated;
249	          keyMarker = objectVersions.NextKeyMarker;
250	          versionIdMarker = objectVersions.NextVersionIdMarker;
251	        }
252	
253	        deleteResponse.Deleted = successfullyDeletedObjectVersions;
254	        setDeleteResponse({
255	          selectedObjects: data,
256	          deleteResponse: deleteResponse || ({} as DeleteObjectsCommandOutput),
257	        });
258	      } else {
259	        const deleteObjectKeys: ObjectIdentifier[] = data.map((object) => ({
260	          Key: getName(object),
261	          ...(showVersioning && { VersionId: getObjectVersionId(object) }),
262	        }));
263	
264	        const deleteResponse = await s3Client.deleteObjects({
265	          Bucket: bucketName,
266	          Delete: { Objects: deleteObjectKeys },
267	        });
268	
269	        setDeleteResponse({
270	          selectedObjects: data,
271	          deleteResponse: deleteResponse || ({} as DeleteObjectsCommandOutput),
272	        });
273	      }
274	
275	      setInProgress(false);
276	      closeModal();
277	      // need new continuation tokens after state of bucket has changed (objects deleted)
278	      refreshTokens?.();
279	      closeObjectSidebar?.();
280	    } catch (err) {
281	      setInProgress(false);
282	      setError(err);
283	    }
284	  };
285	
286	  return (
287	    <Modal
288	      title={getTitle(data, showVersioning, t)}
289	      titleIconVariant="warning"
290	      isOpen={isOpen}
291	      onClose={closeModal}
292	      description={getDescription(showVersioning, t)}
293	      variant={ModalVariant.medium}
294	      actions={[
295	        <ButtonBar
296	          inProgress={inProgress}
297	          errorMessage={error?.message || JSON.stringify(error)}
298	        >
299	          <span>
300	            <Button
301	              variant={ButtonVariant.danger}
302	              onClick={onDelete}
303	              isDisabled={deleteText !== DELETE || inProgress || !!error}
304	              className="pf-v6-u-mr-xs"
305	            >
306	              {t('Delete object')}
307	            </Button>
308	            <Button
309	              variant={ButtonVariant.link}
310	              onClick={closeModal}
311	              className="pf-v6-u-ml-xs"
312	            >
313	              {t('Cancel')}
314	            </Button>
315	          </span>
316	        </ButtonBar>,
317	      ]}
318	    >
319	      <div className="objects-table">
320	        <ListFilter
321	          data={data}
322	          loaded={true}
323	          textInputProps={{ className: 'pf-v6-u-w-50 pf-v6-u-ml-lg' }}
324	        >
325	          {(filteredData): React.ReactNode => (
326	            <PaginatedListPage
327	              filteredData={filteredData}
328	              noData={data.length === 1}
329	              hideFilter
330	              composableTableProps={{
331	                columns: getHeaderColumns(showVersioning, t),
332	                RowComponent: DeleteObjectsTableRow,
333	                extraProps: { foldersPath, showVersioning },
334	                unfilteredData: data as [],
335	                loaded: true,
336	                variant: TableVariant.compact,
337	              }}
338	              paginationProps={{
339	                variant: PaginationVariant.top,
340	                isCompact: true,
341	                dropDirection: 'down',
342	                perPageOptions: [{ title: '10', value: 10 }],
343	                className: 'objects-table-paginate--margin-top',
344	              }}
345	            />
346	          )}
347	        </ListFilter>
348	      </div>
349	      {allowPermanentDeletion && (
350	        <Checkbox
351	          label={
352	            <Trans t={t}>
353	              Skip <i>delete marker</i> and delete object permanently
354	            </Trans>
355	          }
356	          isChecked={permanentDelete}
357	          onChange={(_e, checked) => setPermanentDelete(checked)}
358	          id="permanent-delete-object"
359	          body={
360	            permanentDelete ? (
361	              <Alert
362	                variant={AlertVariant.warning}
363	                isInline
364	                title={t('Caution')}
365	              >
366	                {t(
367	                  'This selection will delete current and all previous versions of the object from the bucket permanently. This object will be lost forever and cannot be restored.'
368	                )}
369	              </Alert>
370	            ) : null
371	          }
372	          className="pf-v6-u-my-sm"
373	        />
374	      )}
375	      <FormGroup
376	        label={getTextInputLabel(t)}
377	        fieldId="delete-objects"
378	        className="pf-v6-u-mt-lg pf-v6-u-mb-sm"
379	      >
380	        <TextInput
381	          value={deleteText}
382	          id="delete-objects"
383	          onChange={(_event, value) => setDeleteText(value)}
384	          type={TextInputTypes.text}
385	          placeholder={DELETE}
386	        />
387	      </FormGroup>
388	    </Modal>
389	  );
390	};
391	
392	export default DeleteObjectsModal;

