219	            VersionIdMarker: versionIdMarker,
220	          });
221	
222	          for (const v of objectVersions?.Versions || []) {
223	            if (v.Key === objectKey)
224	              deleteVersionKeys.push({
225	                Key: objectKey,
226	                VersionId: v.VersionId,
227	              });
228	            else stopFetchEarly = true;
229	          }
230	
231	          for (const d of objectVersions?.DeleteMarkers || []) {
232	            if (d.Key === objectKey)
233	              deleteVersionKeys.push({
234	                Key: objectKey,
235	                VersionId: d.VersionId,
236	              });
237	            else stopFetchEarly = true;
238	          }
239	
240	          // eslint-disable-next-line no-await-in-loop
241	          deleteResponse = await s3Client.deleteObjects({
242	            Bucket: bucketName,
243	            Delete: { Objects: deleteVersionKeys },
244	          });
245	          successfullyDeletedObjectVersions = [
246	            ...successfullyDeletedObjectVersions,
247	            ...(deleteResponse.Deleted || []),
248	          ];
249	          if (deleteResponse.Errors?.length > 0) stopFetchEarly = true;
250	
251	          isTruncated = objectVersions.IsTruncated;
252	          keyMarker = objectVersions.NextKeyMarker;
253	          versionIdMarker = objectVersions.NextVersionIdMarker;
254	        }
255	
256	        deleteResponse.Deleted = successfullyDeletedObjectVersions;
257	        setDeleteResponse({
258	          selectedObjects: data,
259	          deleteResponse: deleteResponse || ({} as DeleteObjectsCommandOutput),
260	        });
261	      } else {
262	        const deleteObjectKeys: ObjectIdentifier[] = data.map((object) => ({
263	          Key: getName(object),
264	          ...(showVersioning && { VersionId: getObjectVersionId(object) }),
265	        }));
266	
267	        const deleteResponse = await s3Client.deleteObjects({
268	          Bucket: bucketName,
269	          Delete: { Objects: deleteObjectKeys },
270	        });
271	
272	        setDeleteResponse({
273	          selectedObjects: data,
274	          deleteResponse: deleteResponse || ({} as DeleteObjectsCommandOutput),
275	        });
276	      }
277	
278	      setInProgress(false);
279	      closeModal();
280	      // need new continuation tokens after state of bucket has changed (objects deleted)
281	      refreshTokens?.();
282	      closeObjectSidebar?.();
283	    } catch (err) {
284	      setInProgress(false);
285	      setError(err);
286	    }
287	  };
